#include <iostream>
using namespace std;
//1
//1 1
//1 2 1
//1 3 3 1
//1 4 6 4 1
//1 5 10 10 5 1
int a[25][25],n;
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		a[i][1]=1;
		a[i][i]=1;
	}
	for(int i=3;i<=n;i++){
		for(int j=2;j<=n;j++){
			a[i][j]=a[i-1][j-1]+a[i-1][j];
		}
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=i;j++){
			cout<<a[i][j]<<" ";
		}
		cout<<"\n";
	}
	return 0;
}
